import { useEffect, useState } from 'react';
import api from '../../services/api';
import toast from 'react-hot-toast';

export default function UsuarioList() {
  const [usuarios, setUsuarios] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editingUser, setEditingUser] = useState(null);
  const [formData, setFormData] = useState({ nombre: '', email: '', password: '', rol: 'vendedor' });

  const fetchUsuarios = async () => {
    try {
      const res = await api.get('/usuarios');
      setUsuarios(res.data);
    } catch (error) {
      toast.error('Error al cargar usuarios');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchUsuarios(); }, []);

  const handleToggleActivo = async (id, activoActual) => {
    try {
      await api.patch(`/usuarios/${id}/toggle-activo`, { activo: !activoActual });
      toast.success(`Usuario ${!activoActual ? 'activado' : 'desactivado'}`);
      fetchUsuarios();
    } catch (error) {
      toast.error('Error al cambiar estado');
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm('¿Eliminar usuario?')) {
      try {
        await api.delete(`/usuarios/${id}`);
        toast.success('Usuario eliminado');
        fetchUsuarios();
      } catch (error) { toast.error('Error al eliminar'); }
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingUser) {
        await api.put(`/usuarios/${editingUser.id}`, { nombre: formData.nombre, email: formData.email, rol: formData.rol });
        toast.success('Usuario actualizado');
      } else {
        await api.post('/usuarios', formData);
        toast.success('Usuario creado');
      }
      setShowForm(false);
      setEditingUser(null);
      fetchUsuarios();
    } catch (error) { toast.error(error.response?.data?.error || 'Error'); }
  };

  if (loading) return <div>Cargando...</div>;

  return (
    <div>
      <div className="flex justify-between items-center mb-4">
        <h1 className="text-2xl font-bold">Gestión de Usuarios</h1>
        <button onClick={() => { setEditingUser(null); setFormData({ nombre: '', email: '', password: '', rol: 'vendedor' }); setShowForm(true); }} className="bg-green-600 text-white px-4 py-2 rounded">Nuevo Usuario</button>
      </div>
      <div className="overflow-x-auto">
        <table className="min-w-full bg-white border">
          <thead><tr className="bg-gray-100"><th>Nombre</th><th>Email</th><th>Rol</th><th>Estado</th><th>Acciones</th></tr></thead>
          <tbody>
            {usuarios.map(u => (
              <tr key={u.id}>
                <td className="py-2 px-4 border">{u.nombre}</td>
                <td className="py-2 px-4 border">{u.email}</td>
                <td className="py-2 px-4 border">{u.rol}</td>
                <td className="py-2 px-4 border">{u.activo ? 'Activo' : 'Inactivo'}</td>
                <td className="py-2 px-4 border">
                  <button onClick={() => { setEditingUser(u); setFormData({ nombre: u.nombre, email: u.email, password: '', rol: u.rol }); setShowForm(true); }} className="text-blue-600 mr-2">Editar</button>
                  <button onClick={() => handleToggleActivo(u.id, u.activo)} className="text-yellow-600 mr-2">{u.activo ? 'Desactivar' : 'Activar'}</button>
                  <button onClick={() => handleDelete(u.id)} className="text-red-600">Eliminar</button>
                </td>
               </tr>
            ))}
          </tbody>
        </table>
      </div>
      {showForm && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex justify-center items-center">
          <div className="bg-white p-6 rounded shadow-lg w-96">
            <h2 className="text-xl font-bold mb-4">{editingUser ? 'Editar Usuario' : 'Nuevo Usuario'}</h2>
            <form onSubmit={handleSubmit}>
              <input type="text" placeholder="Nombre" value={formData.nombre} onChange={e => setFormData({...formData, nombre: e.target.value})} className="w-full border p-2 mb-2 rounded" required />
              <input type="email" placeholder="Email" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className="w-full border p-2 mb-2 rounded" required />
              {!editingUser && <input type="password" placeholder="Contraseña" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} className="w-full border p-2 mb-2 rounded" required />}
              <select value={formData.rol} onChange={e => setFormData({...formData, rol: e.target.value})} className="w-full border p-2 mb-4 rounded">
                <option value="vendedor">Vendedor</option>
                <option value="admin">Administrador</option>
              </select>
              <div className="flex justify-end space-x-2">
                <button type="button" onClick={() => setShowForm(false)} className="bg-gray-400 text-white px-4 py-2 rounded">Cancelar</button>
                <button type="submit" className="bg-blue-600 text-white px-4 py-2 rounded">Guardar</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
